/*
输入并求出最大值(si)
循环枚举查看是否满足条件（和平）
所需函数：exgcd, check 
*/ 
#include <bits/stdc++.h>
#define int long long
using namespace std;
int n, s[25], p[25], l[25], maxx;
int exgcd (int a, int b, int &x, int &y) {
	if (!b) {
		x = 1;
		y = 0;
		return a;
	}
	int g = exgcd (b, a % b, y, x);
	y -= a / b * x;
	return g;
}
bool check (int m) {
	for (int i = 1; i <= n; i++) {
		for (int j = i + 1; j <= n; j++) {
			int a = p[i] - p[j], b = m, c = s[j] - s[i], x, y;
			int g = exgcd (a, b, x, y);
			if (c % g) {
				continue;
			}
			a /= g;
			b /= g;
			c /= g;
			if (b < 0) {
				b = -b;
			}
			x = (x * c % b + b) % b;
			if (x <= l[i] && x <= l[j]) {
				return false;
			}
		}
	}
	return true;
}
signed main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> s[i] >> p[i] >> l[i];
		maxx = max (maxx, s[i]);
	}
	for (int i = maxx;; i++) {
		if (check (i)) {
			cout << i;
			return 0;
		}
	}
	return 0;
}
